@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_41305cfd586644a798cdee8d9bb50941.Data
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Only administrators can view this page.</p>

@if (users is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Display Name</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.DisplayName</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();

        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }

        users = result;
    }
}

@page "/directory"
@rendermode InteractiveServer
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_41305cfd586644a798cdee8d9bb50941.Data
@inject UserManager<ApplicationUser> UserManager

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p>Accessible to all authenticated employees.</p>

@if (employees is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var employee in employees)
            {
                <tr>
                    <td>@employee.DisplayName</td>
                    <td>@employee.Email</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ApplicationUser>? employees;

    protected override async Task OnInitializedAsync()
    {
        await Task.CompletedTask;
        employees = UserManager.Users.OrderBy(u => u.DisplayName).ToList();
    }
}

@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        Navigation.NavigateTo($"Account/Login?ReturnUrl={Uri.EscapeDataString(Navigation.Uri)}", forceLoad: true);
    }
}

